INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('5c1f4f21-151a-4b22-a335-5ef961d9e99f', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content', 'Technical', 'Evaluates the depth and originality of the engineering solution, including problem formulation, design decisions, and mastery of relevant tools and methods.', 30, 35, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Strong problem definition with well-justified design choices. Demonstrates deep domain knowledge."},{"min":21,"max":26,"label":"Good","description":"Problem is clearly stated. Design decisions are reasonable with minor justification gaps."},{"min":13,"max":20,"label":"Developing","description":"Problem statement exists but technical depth is shallow."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition. Design decisions are not supported."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('15dca296-abd2-4fd9-adb3-ff2d66b91858', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Written Report Quality', 'Report', 'Assesses poster layout, visual quality, labelling, and the accessibility of technical content for both technical and non-technical readers.', 30, 25, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Report is well-structured with clear sections, proper references, and professional formatting."},{"min":21,"max":26,"label":"Good","description":"Report covers required sections adequately. Formatting is mostly consistent."},{"min":13,"max":20,"label":"Developing","description":"Report structure is present but sections lack depth or proper citations."},{"min":0,"max":12,"label":"Insufficient","description":"Report is incomplete, poorly formatted, or missing critical sections."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('01b94576-b441-4c66-ac35-be4aa17effa3', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '3a305bed-e865-444f-a3a3-c92302bd93cf', 'delivery', 'Oral Presentation', 'Oral', 'Assesses oral clarity, pacing, audience adaptation, and the quality of Q&A responses during the presentation.', 30, 25, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Clear, confident delivery with good pacing. Questions answered accurately and concisely."},{"min":21,"max":26,"label":"Good","description":"Presentation is understandable with adequate pacing. Most questions handled well."},{"min":13,"max":20,"label":"Developing","description":"Delivery is hesitant or rushed. Audience engagement is limited."},{"min":0,"max":12,"label":"Insufficient","description":"Disorganized presentation. Questions frequently answered incorrectly."}]', 3) ON CONFLICT DO NOTHING;
