INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('0feebb9e-7f45-4128-a54b-5d8d078d7694', '10078594-2707-4c3f-a212-42add04fbd84', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content', 'Technical', 'Evaluates the depth and originality of the engineering solution, including problem formulation, design decisions, and mastery of relevant tools and methods.', 30, 35, '#F59E0B', '[{"min":22,"max":30,"label":"Proficient","description":"Sound engineering approach with adequate technical justification."},{"min":14,"max":21,"label":"Developing","description":"Technical content is present but reasoning is not well-supported."},{"min":0,"max":13,"label":"Below Standard","description":"Lacks meaningful technical contribution."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('499fa39c-6170-4adb-a41b-18f3f16b2aff', '10078594-2707-4c3f-a212-42add04fbd84', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Written Report', 'Report', 'Assesses poster layout, visual quality, labelling, and the accessibility of technical content for both technical and non-technical readers.', 30, 25, '#22C55E', '[{"min":22,"max":30,"label":"Proficient","description":"Written report is organized and covers key design decisions."},{"min":14,"max":21,"label":"Developing","description":"Report exists but structure or content is incomplete."},{"min":0,"max":13,"label":"Below Standard","description":"Report is largely missing or disorganized."}]', 2) ON CONFLICT DO NOTHING;
