INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('52f96a98-1ac8-4b6e-aa3c-02ab77905c16', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', '7283938c-881e-46e5-a432-793287f19248', 'system_design', 'Software Architecture', 'Design', 'Assesses architectural soundness, modularity, scalability, and justification of design decisions and component boundaries.', 25, 30, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Textbook-quality architecture. Components are cohesive with well-defined interfaces."},{"min":17,"max":21,"label":"Good","description":"Architecture is functional with reasonable separation of concerns."},{"min":12,"max":16,"label":"Developing","description":"Monolithic or poorly factored. Dependencies are tangled."},{"min":0,"max":11,"label":"Insufficient","description":"No coherent architecture. Code organization is arbitrary."}]', 2) ON CONFLICT DO NOTHING;
