INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('3827321e-25d3-4ec5-ab6a-d8fb8d5f65fd', 'e77bf882-fc32-461c-acab-6ee1696df0c7', '10f52721-c639-4184-a0c4-1493bd620bfd', 'preliminary_report', 'Preliminary Design Report (ODR)', 'Report', 'Evaluates completeness of the preliminary design report, mission definition clarity, and feasibility of the proposed design.', 25, 25, '#6366F1', '[{"min":22,"max":25,"label":"Excellent","description":"Report is comprehensive with clear mission definition and feasible preliminary design."},{"min":17,"max":21,"label":"Good","description":"Report covers key design elements with adequate justification."},{"min":12,"max":16,"label":"Developing","description":"Report structure is present but design rationale is weak."},{"min":0,"max":11,"label":"Insufficient","description":"Report is incomplete or missing critical sections."}]', 1) ON CONFLICT DO NOTHING;
