INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('585f50bf-9fb8-4d91-a04d-ec0d9d96f763', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Atık Yağlardan Biyodizel Üretim Optimizasyonu', 5, '[{"name":"Selin Akay","order":1},{"name":"Emrah Polat","order":2},{"name":"Defne Çetin","order":3},{"name":"Alper Bayraktar","order":4}]', 'Mehmet Kaya', 'Galatasaray Lisesi', 'Evsel atık kızartma yağlarından bazik katalizör ile transesterifikasyon yöntemiyle biyodizel üretimi. Metanol-yağ oranı, sıcaklık ve katalizör miktarı Taguchi yöntemiyle optimize edilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5b69ec00-b61b-4bf1-a938-c4645c26ab9b', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Deprem Erken Uyarı Sensör Ağı Prototipi', 6, '[{"name":"Doruk Acar","order":1},{"name":"Taylan Ergin","order":2},{"name":"Sıla Yılmazer","order":3},{"name":"Elif Naz Balcı","order":4}]', 'Dr. Merve Yıldırım', 'Ankara Fen Lisesi', 'MEMS ivmeölçer tabanlı düşük maliyetli sismik sensör düğümleri; P-dalgası algılandığında LoRa ağı üzerinden merkeze uyarı gönderen dağıtık erken uyarı sistemi prototipi.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ec36e04f-bc08-484d-aec8-77976e40ccf2', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Meyve Olgunluk Tespiti için Hiperspektral Görüntüleme', 7, '[{"name":"Melike Savaş","order":1},{"name":"Altan Çevik","order":2},{"name":"Azra Evren","order":3},{"name":"Canberk Yıldız","order":4}]', 'Selin Karadeniz', 'İstanbul Atatürk Fen Lisesi', '400-1000 nm aralığında hiperspektral kamera ile domates olgunluk seviyesinin tahribatsız tespiti. PLS-DA sınıflandırıcı ile dört olgunluk aşaması %93 doğrulukla ayırt edilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('71359fc5-fa1d-49e0-a508-7791072924f7', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Su Kirliliğinin Yapay Zeka ile İzlenmesi', 8, '[{"name":"Ozan Çelebi","order":1},{"name":"Kaan Avcı","order":2},{"name":"Selçuk Taner","order":3}]', 'Ahmet Çelik', 'İzmir Fen Lisesi', 'Nehir yüzeyinden alınan drone görüntülerinde yağ tabakası ve atık birikimi tespiti yapan segmentasyon modeli. U-Net mimarisi ile piksel bazında %91 IoU değerine ulaşılmıştır.') ON CONFLICT DO NOTHING;
