INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('7c08441a-9b1c-43b1-ab4b-a6d204c8f90d', '6c44b363-4522-4cad-a251-06484b72b164', 'Phased Array Antenna for 28 GHz mmWave 5G', 1, '[{"name":"Gabriel Locke","order":1},{"name":"Mia Howard","order":2},{"name":"Elise Whitfield","order":3},{"name":"Declan Holt","order":4},{"name":"Caleb Richardson","order":5}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A 16-element patch phased array on Rogers RO4003C with corporate feed network and 5-bit digital phase shifters, achieving ±45° beam scanning with 22 dBi peak gain at 28 GHz.') ON CONFLICT DO NOTHING;
