INSERT INTO jury_feedback (period_id, juror_id, rating, comment, is_public) VALUES
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'aaa0da50-6432-47e0-ab48-b01ca823ef19', 4, NULL, false),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '9a21397b-552a-4b00-a5c4-15a0982436b1', 5, 'Çok kullanışlı bir sistem. Poster günü sorunsuz değerlendirme yapabildik.', true),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '868057b9-f2e0-4db1-a4e9-e258d25f84e1', 4, 'Arayüz sade ve hızlı. Rubrik bandları çok yardımcı oldu.', true),
('952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'aaa0da50-6432-47e0-ab48-b01ca823ef19', 5, NULL, false),
('952dd05e-8ff2-44a7-a13b-9a22958f57fb', '7d1bbec7-493f-4e1a-aee5-be30df51db49', 4, 'Her seferinde daha iyi oluyor.', true),
('e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '47dcf645-bcf8-407e-a86e-f0e506495726', 5, 'Replaced our old paper-based system entirely. The export feature saves hours.', true),
('e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '44e14170-d567-4ad4-a771-cd269d538a2f', 4, 'Solid tool. Configurable criteria made it easy to adapt.', true),
('e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', 'cdfec676-c0dc-4c35-a5d8-79ba609e397d', 5, 'Clean and intuitive. Scoring 12 projects took less than an hour.', true),
('b90e1112-88c7-44fa-a275-25bc0ad2d96d', '47dcf645-bcf8-407e-a86e-f0e506495726', 5, NULL, false),
('b90e1112-88c7-44fa-a275-25bc0ad2d96d', '44e14170-d567-4ad4-a771-cd269d538a2f', 3, NULL, false),
('0e963024-a53f-4722-a9e0-5db7a47b4419', '47dcf645-bcf8-407e-a86e-f0e506495726', 4, NULL, false),
('0e963024-a53f-4722-a9e0-5db7a47b4419', '44e14170-d567-4ad4-a771-cd269d538a2f', 5, 'Third semester using VERA. It keeps getting better.', true),
('e77bf882-fc32-461c-acab-6ee1696df0c7', 'cec22180-51e9-4924-a2d0-6bca4aeb0028', 5, 'Yüzlerce takımı hızlıca değerlendirdik. Sistem çok stabil.', true),
('e77bf882-fc32-461c-acab-6ee1696df0c7', '618aec67-dbed-41bf-ac48-c600f70c9fa5', 4, 'Yarışma ortamında çok pratik. QR ile giriş mükemmel.', true),
